import Marquee from "react-fast-marquee";
import { motion } from "framer-motion";

const videoItems = [
  "/assets/videos/cooking.mp4",
  "/assets/videos/vid2.mp4",
  "/assets/videos/vid3.mp4",
  "/assets/videos/vid5.mp4",
  "/assets/videos/vid6.mp4"
];

const imageItems = [
  "/assets/amb.jpg",
  "/assets/apr.jpg",
  "/assets/ballent.jpg",
  "/assets/bl.jpg",
  "/assets/bn.jpg",
  "/assets/dj.jpg",
  "/assets/dri.jpg",
  "/assets/f1.jpg",
  "/assets/grp.jpg",
  "/assets/nod.jpg",
  "/assets/pic.jpg",
  "/assets/piz.jpg"
];

const MovingGallery = () => {
  return (
    <>
      <motion.section 
        initial={{ opacity: 0 }}
        whileInView={{ opacity: 1 }}
        className="py-24 bg-black overflow-hidden relative"
      >
        <div className="container mx-auto px-6 text-center mb-24">
          <motion.span 
            className="block font-accent text-gold text-lg tracking-[0.3em] uppercase mb-8 px-8 py-4 bg-black rounded-full"
            whileHover={{ scale: 1.05 }}
          >
            Experience The Vibe
          </motion.span>
          <motion.h2 
            className="text-5xl md:text-6xl lg:text-7xl font-heading text-white leading-none mb-4"
            initial={{ y: 50, opacity: 0 }}
            whileInView={{ y: 0, opacity: 1 }}
          >
            Corridor in Motion
          </motion.h2>
        </div>

        {/* Video Marquee - Zero Gap */}
        <div className="w-full">
          <Marquee speed={30} direction="left" gradient={false} pauseOnHover className="!gap-0 !px-8">
            {videoItems.concat(videoItems).map((src, i) => (
              <video
                key={i}
                src={src}
                className="!mr-0 !w-[220px] !h-[380px] md:!w-[280px] md:!h-[500px] object-cover rounded-3xl shadow-2xl bg-gradient-to-b from-black/20"
                muted
                autoPlay
                loop
                playsInline
                preload="auto"
              />
            ))}
          </Marquee>
        </div>
      </motion.section>

      {/* Image Marquees */}
      <motion.section 
        initial={{ opacity: 0 }}
        whileInView={{ opacity: 1 }}
        className="py-20 bg-gradient-to-b from-black to-black/50 overflow-hidden"
      >
        {/* LTR Images */}
        <div className="w-full mb-8">
          <Marquee speed={70} gradient={false} pauseOnHover className="!gap-0 !px-8">
            {imageItems.slice(0, 11).map((src, i) => (
              <motion.img
                key={i}
                src={src}
                className="!mr-0 !w-[320px] md:!w-[400px] !h-[220px] md:!h-[280px] object-cover rounded-2xl shadow-2xl grayscale hover:grayscale-0 border-4 border-transparent hover:border-gold/50 mx-[-4px]"
                whileHover={{ scale: 1.05 }}
                transition={{ duration: 0.4 }}
                loading="lazy"
              />
            ))}
          </Marquee>
        </div>

        {/* RTL Images */}
        <div className="w-full">
          <Marquee speed={70} direction="right" gradient={false} pauseOnHover className="!gap-0 !px-8">
            {imageItems.slice(0, 7).map((src, i) => (
              <motion.img
                key={"r" + i}
                src={src}
                className="!mr-0 !w-[320px] md:!w-[400px] !h-[220px] md:!h-[280px] object-cover rounded-2xl shadow-2xl grayscale hover:grayscale-0 border-4 border-transparent hover:border-gold/50 mx-[-4px]"
                whileHover={{ scale: 1.05 }}
                transition={{ duration: 0.4 }}
                loading="lazy"
              />
            ))}
          </Marquee>
        </div>
      </motion.section>
    </>
  );
};

export default MovingGallery;
